// Post-process the code generated by `@atproto/lex` (ts-lex build) to honor the
// lexicons' `nullable: true` markers.
//
// The generator (@atproto/lex 0.3.0) drops `nullable` entirely: a nullable
// field becomes a plain `l.optional(l.string(...))`, which accepts `undefined`
// but rejects an explicit `null`. The live API legitimately returns `null` for
// those fields, so a strict client (@atproto/lex-client) throws
// "Expected string value type (got null)". @atproto/lex-schema ships an
// `l.nullable(...)` combinator the generator never emits — this script inserts
// it, and mirrors the change into the explicit generated types (`| null`).
//
// It is schema-aware: each generated object schema is walked in parallel with
// its source lexicon definition, so a field is wrapped only where THAT schema
// marks it nullable (field names like `publishedAt` are nullable in one view
// and required in another — a by-name rewrite would be wrong).
//
// Edits are pure text inserts located via the TS AST, so the `/*#__PURE__*/`
// pragmas and formatting survive (the TS printer would rewrite the whole file).
// Method-output types are `InferPayload<typeof $output>`, derived from the
// runtime validator, so wrapping the validator updates them automatically; only
// the explicit `l.typedObject<T>` def types need the `| null` annotation.
//
// Run after `lex:build` (wired into `pnpm generate`). Idempotent.

import { readdirSync, readFileSync, statSync, writeFileSync } from "node:fs";
import { dirname, join, resolve } from "node:path";
import { fileURLToPath } from "node:url";
import ts from "typescript";

const ROOT = resolve(dirname(fileURLToPath(import.meta.url)), "..");
const LEX_SRC = resolve(ROOT, "../../lexicons");
const GEN_DIR = join(ROOT, "src/lexicons");

// ---------------------------------------------------------------------------
// Load source lexicons, keyed by NSID.
// ---------------------------------------------------------------------------

const lexicons = new Map();
(function eachJson(dir) {
  for (const entry of readdirSync(dir)) {
    const p = join(dir, entry);
    if (statSync(p).isDirectory()) eachJson(p);
    else if (entry.endsWith(".json")) {
      const json = JSON.parse(readFileSync(p, "utf8"));
      if (json && json.id) lexicons.set(json.id, json);
    }
  }
})(LEX_SRC);

/** The `properties` map of an object/record schema, else null. */
function propsOf(schema) {
  if (!schema || typeof schema !== "object") return null;
  if (schema.type === "object" && schema.properties) return schema.properties;
  if (schema.type === "record" && schema.record?.properties) return schema.record.properties;
  return null;
}

/** Nested object properties reachable through a property schema (object, or array-of-object). */
function nestedProps(propSchema) {
  if (!propSchema || typeof propSchema !== "object") return null;
  if (propSchema.type === "object" && propSchema.properties) return propSchema.properties;
  if (propSchema.type === "array") return propsOf(propSchema.items);
  return null;
}

function defProps(nsid, defName) {
  return propsOf(lexicons.get(nsid)?.defs?.[defName]);
}
function mainIoProps(nsid, which) {
  return propsOf(lexicons.get(nsid)?.defs?.main?.[which]?.schema);
}

// ---------------------------------------------------------------------------
// AST helpers.
// ---------------------------------------------------------------------------

function isLCall(node, names) {
  return (
    ts.isCallExpression(node) &&
    ts.isPropertyAccessExpression(node.expression) &&
    ts.isIdentifier(node.expression.expression) &&
    node.expression.expression.text === "l" &&
    names.includes(node.expression.name.text)
  );
}

function memberName(name) {
  if (name && (ts.isIdentifier(name) || ts.isStringLiteral(name))) return name.text;
  return null;
}

/** Unwrap l.optional/l.nullable/l.array to the inner `l.object({...})` object literal, if any. */
function innerObjectLiteral(node) {
  let cur = node;
  while (isLCall(cur, ["optional", "nullable", "array"])) cur = cur.arguments[0];
  if (isLCall(cur, ["object"])) {
    const arg = cur.arguments[0];
    if (arg && ts.isObjectLiteralExpression(arg)) return arg;
  }
  return null;
}

const alreadyNullable = (node) => isLCall(node, ["nullable"]);

// ---------------------------------------------------------------------------
// Transform each generated .ts file.
// ---------------------------------------------------------------------------

function eachTs(dir, out = []) {
  for (const entry of readdirSync(dir)) {
    const p = join(dir, entry);
    if (statSync(p).isDirectory()) eachTs(p, out);
    else if (entry.endsWith(".ts")) out.push(p);
  }
  return out;
}

let filesChanged = 0;
let validatorEdits = 0;
let typeEdits = 0;

for (const file of eachTs(GEN_DIR)) {
  const text = readFileSync(file, "utf8");
  const sf = ts.createSourceFile(file, text, ts.ScriptTarget.Latest, true, ts.ScriptKind.TS);
  const inserts = []; // { pos, text }

  const wrapValue = (valNode) => {
    if (alreadyNullable(valNode)) return;
    inserts.push({ pos: valNode.getStart(sf), text: "l.nullable(" });
    inserts.push({ pos: valNode.getEnd(), text: ")" });
    validatorEdits++;
  };

  // Walk a generated object literal in parallel with its source properties.
  const walkValidator = (objLit, srcProps) => {
    for (const prop of objLit.properties) {
      if (!ts.isPropertyAssignment(prop)) continue;
      const name = memberName(prop.name);
      const srcProp = name ? srcProps[name] : null;
      if (!srcProp) continue;
      if (srcProp.nullable === true) wrapValue(prop.initializer);
      const childProps = nestedProps(srcProp);
      if (childProps) {
        const childObj = innerObjectLiteral(prop.initializer);
        if (childObj) walkValidator(childObj, childProps);
      }
    }
  };

  // Walk a generated type literal in parallel with its source properties.
  const walkType = (typeLit, srcProps) => {
    for (const member of typeLit.members) {
      if (!ts.isPropertySignature(member) || !member.type) continue;
      const name = memberName(member.name);
      const srcProp = name ? srcProps[name] : null;
      if (!srcProp) continue;
      if (srcProp.nullable === true && !/\bnull\b/.test(member.type.getText(sf))) {
        inserts.push({ pos: member.type.getEnd(), text: " | null" });
        typeEdits++;
      }
      const childProps = nestedProps(srcProp);
      if (childProps && ts.isTypeLiteralNode(member.type)) walkType(member.type, childProps);
    }
  };

  // First pass: map explicit def type names (l.typedObject<T>(nsid, 'def', ...)) to their schema.
  const typeToProps = new Map();
  const collectTypeMap = (node) => {
    if (
      isLCall(node, ["typedObject"]) &&
      node.typeArguments?.[0] &&
      ts.isTypeReferenceNode(node.typeArguments[0]) &&
      ts.isIdentifier(node.typeArguments[0].typeName)
    ) {
      const nsidArg = node.arguments[0];
      const defArg = node.arguments[1];
      // arg[0] is the `$nsid` identifier; resolve it from this file's const below.
      if (defArg && ts.isStringLiteral(defArg) && nsidArg && ts.isIdentifier(nsidArg)) {
        typeToProps.set(node.typeArguments[0].typeName.text, { defName: defArg.text });
      }
    }
    ts.forEachChild(node, collectTypeMap);
  };
  collectTypeMap(sf);

  // Resolve this file's NSID from `const $nsid = '...'`.
  let fileNsid = null;
  const findNsid = (node) => {
    if (
      ts.isVariableDeclaration(node) &&
      ts.isIdentifier(node.name) &&
      node.name.text === "$nsid" &&
      node.initializer &&
      ts.isStringLiteral(node.initializer)
    ) {
      fileNsid = node.initializer.text;
    }
    ts.forEachChild(node, findNsid);
  };
  findNsid(sf);
  if (!fileNsid) {
    continue; // no schemas here (e.g. index.ts)
  }

  // Second pass: schema roots.
  const visit = (node) => {
    // Def objects: l.typedObject($nsid, 'defName', l.object({...}))
    if (isLCall(node, ["typedObject"])) {
      const defArg = node.arguments[1];
      const objLit = node.arguments[2] && innerObjectLiteral(node.arguments[2]);
      if (defArg && ts.isStringLiteral(defArg) && objLit) {
        const srcProps = defProps(fileNsid, defArg.text);
        if (srcProps) walkValidator(objLit, srcProps);
      }
    }

    // Method output/input payloads: export const $output = l.jsonPayload({...})
    if (
      ts.isVariableDeclaration(node) &&
      ts.isIdentifier(node.name) &&
      (node.name.text === "$output" || node.name.text === "$input") &&
      node.initializer &&
      isLCall(node.initializer, ["jsonPayload"])
    ) {
      const arg = node.initializer.arguments[0];
      const objLit = arg && ts.isObjectLiteralExpression(arg) ? arg : null;
      if (objLit) {
        const which = node.name.text === "$output" ? "output" : "input";
        const srcProps = mainIoProps(fileNsid, which);
        if (srcProps) walkValidator(objLit, srcProps);
      }
    }

    // Explicit def types: type PublicationView = { ... }
    if (ts.isTypeAliasDeclaration(node) && ts.isTypeLiteralNode(node.type)) {
      const mapped = typeToProps.get(node.name.text);
      if (mapped) {
        const srcProps = defProps(fileNsid, mapped.defName);
        if (srcProps) walkType(node.type, srcProps);
      }
    }

    ts.forEachChild(node, visit);
  };
  visit(sf);

  if (!inserts.length) continue;
  inserts.sort((a, b) => b.pos - a.pos); // apply right-to-left; pure inserts compose
  let next = text;
  for (const e of inserts) next = next.slice(0, e.pos) + e.text + next.slice(e.pos);
  writeFileSync(file, next);
  filesChanged++;
}

console.log(
  `patch-nullable: wrapped ${validatorEdits} validator(s), annotated ${typeEdits} type(s) across ${filesChanged} file(s).`,
);
